from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/query_params', methods=['GET'])
def handle_query_params():
    params = request.args.to_dict()
    return jsonify({
        "message": "Query parameters received successfully!",
        "parameters": params
    })

if __name__ == '__main__':
    app.run(debug=True)
